class Solution {
private:
    // Precompute closest neighbors
    vector<int> precompute_closest(const vector<long long>& nums) {
        int n = nums.size();
        vector<int> closest_neighbors(n);
        for (int x = 0; x < n; ++x) {
            long long min_diff = -1;
            int closest_y = -1;

            // Check left neighbor (y = x-1)
            if (x > 0) {
                long long diff = abs(nums[x] - nums[x - 1]);
                min_diff = diff;
                closest_y = x - 1;
            }

            // Check right neighbor (y = x+1)
            if (x < n - 1) {
                long long diff = abs(nums[x] - nums[x + 1]);
                if (closest_y == -1 || diff < min_diff || (diff == min_diff && (x + 1) < closest_y)) {
                    min_diff = diff;
                    closest_y = x + 1;
                } else if (closest_y != -1 && diff == min_diff) {
                    // Tie-breaking: choose smaller index
                    if ((x + 1) < closest_y) {
                        closest_y = x + 1;
                    }
                }
            }
            closest_neighbors[x] = closest_y;
        }
        return closest_neighbors;
    }

