    // D[l] = 0.
    // D[x] = min(D[y] + 1) where y is a neighbor reachable from x via closest moves in the path.

    // Since Type 2 moves are deterministic (x -> closest(x)), we can model this as a path in a specific directed graph.
    // The graph G_closest has edges x -> closest(x) with weight 1.
    // Since every node has an out-degree of exactly 1, this graph is a set of functional components (paths leading into cycles, or paths ending).
    // Since N is finite, we must eventually enter a cycle or hit an endpoint if the definition allowed it (here, it's always defined).

    // Since we are looking for l_i -> r_i, the path must traverse nodes $x_0=l_i, x_1, x_2, \dots, x_k=r_i$.
    // The cost is $\sum_{j=0}^{k-1} \text{Cost}(x_j \to x_{j+1})$.

    // If we ONLY use Type 2 moves:
    // Cost(l -> r) = shortest path in G_closest from l to r.

    // If we mix moves:
    // Cost(l -> r) = min over all intermediate nodes $k$:
    //   Cost(l -> k using G_closest) + Cost(k -> r using Type 1 jump)
    // OR
    //   Cost(l -> r using G_closest)

    // ShortestPath(l -> r) in G_closest:
    // Since G_closest is deterministic, the path is unique if we always follow the single outgoing edge.
    // Path: $l \to c(l) \to c(c(l)) \to \dots$
    // We can use binary lifting (LCA style) to quickly jump $2^k$ steps.

    vector<vector<int>> up; // up[i][k] = node reached from i after 2^k closest moves
    vector<int> dist_from_l; // Used if we want to compute distances from l, but here we need path length.

