        int max_log = 0;
        while ((1 << max_log) <= n) {
            max_log++;
        }
        max_log--;

        up.assign(n, vector<int>(max_log + 1, -1));

        for (int i = 0; i < n; ++i) {
            up[i][0] = closest_neighbors[i];
        }

        for (int k = 1; k <= max_log; ++k) {
            for (int i = 0; i < n; ++i) {
                if (up[i][k - 1] != -1) {
                    up[i][k] = up[up[i][k - 1]][k - 1];
                }
            }
        }
    }

