    // This is tricky because the path might enter a cycle. If target is in the path, the cost is the path length.
    // If target is in a cycle, we might reach it.
    // Since all moves are 1, we can use simple iterative traversal up to N steps, which covers any simple path.
    long long path_length_closest(int start, int target, const vector<int>& closest_neighbors, int n) {
        if (start == target) return 0;

        vector<int> visited(n, -1);
        vector<int> depth(n, -1);

