        while (current != -1 && steps <= n) {
            if (current == target) {
                return steps;
            }

            if (visited[current] != -1) {
                // Cycle detected and target not reached
                return -1; 
            }

            visited[current] = steps;
            current = closest_neighbors[current];
            steps++;
        }

        return -1; // Should not happen if N is the bound and we handle cycles correctly.
    }


