using namespace std;

// Helper function to compute closest(x)
int find_closest(int x, const vector<long long>& nums) {
    int n = nums.size();
    if (n == 1) return 0;

    int best_y = -1;
    // Use LLONG_MAX for initialization since differences can be large
    long long min_diff = LLONG_MAX; 

    // Check neighbors: x-1 and x+1
    int candidates[2];
    int count = 0;

    if (x > 0) {
        candidates[count++] = x - 1;
    }
    if (x < n - 1) {
        candidates[count++] = x + 1;
    }

    if (count == 0) return x; 

    for (int i = 0; i < count; ++i) {
        int y = candidates[i];
        long long diff = abs(nums[x] - nums[y]);

        if (diff < min_diff) {
            min_diff = diff;
            best_y = y;
        } else if (diff == min_diff) {
            // If diff is the same, choose the smaller index
            if (best_y == -1 || y < best_y) {
                best_y = y;
            }
        }
    }
    return best_y;
}

// Precompute closest(x) for all x
vector<int> precompute_closest(const vector<long long>& nums) {
    int n = nums.size();
    vector<int> closest(n);
    for (int i = 0; i < n; ++i) {
        closest[i] = find_closest(i, nums);
    }
    return closest;
}

/**
 * @brief Solves the minimum cost path problem.
 * 
 * Time Complexity: O(N + Q * N) where N is nums.length and Q is queries.length.
 * This is potentially too slow for N, Q = 10^5, but implements the required shortest path logic derived from the problem rules.
 */
std::vector<long long> solve(std::vector<long long> nums, std::vector<std::vector<long long>> queries) {
    int N = nums.size();
    if (N == 0) return std::vector<long long>();

    // 1. Precompute closest(x)
    vector<int> C = precompute_closest(nums);

    std::vector<long long> results;

    for (const auto& query : queries) {
        int l = (int)query[0];
        int r = (int)query[1];

        // Initialize minimum cost: Direct jump l -> r
        long long min_cost = abs(nums[l] - nums[r]);

        // 2. BFS to find D_l[x]: Shortest path distance from l to all x using only cost-1 edges (x -> C[x])
        // Since edge weights are 1, BFS works.
        std::vector<int> D(N, -1); // -1 means unvisited/infinity distance
        std::queue<int> q;

        D[l] = 0;
        q.push(l);

        while (!q.empty()) {
            int x = q.front();
            q.pop();

            // The only cost-1 outgoing edge from x is to C[x]
            int y = C[x];

            if (D[y] == -1) {
                D[y] = D[x] + 1;
                q.push(y);
            }
        }

        // 3. Check the alternative paths: min_x ( D_l[x] + |nums[x] - nums[r]| )
        for (int x = 0; x < N; ++x) {
            if (D[x] != -1) {
                // D[x] is the cost to reach x using only cost 1 moves from l
                // |nums[x] - nums[r]| is the cost of the final jump from x to r
                long long current_path_cost = (long long)D[x] + abs(nums[x] - nums[r]);
                min_cost = std::min(min_cost, current_path_cost);
            }
        }

        results.push_back(min_cost);
    }

    return results;
