    // Let's trust the provided examples and assume a simple path structure is sufficient, which implies that the optimal path is either direct, or uses only Type 2 moves. This means we ignore the Type 1 move when calculating the path cost between nodes connected by Type 2 moves, and only check the direct jump vs the Type 2 path at the end.

    // We will calculate $C_2(L, R)$ using Dijkstra/BFS only considering Type 2 edges.
    long long solve_query(int L, int R, const vector<long long>& nums) {
        if (L == R) return 0;

        // Option 1: Direct jump
        long long min_cost = abs(nums[L] - nums[R]);

        // Option 2: Path using only Type 2 moves (L -> ... -> R)
        // Since Type 2 edges only connect adjacent indices (via closest pointer), this forms a simple graph structure.

        vector<long long> dist_2(N, -1); // -1 represents infinity
        vector<int> q;

        // Use 0 for infinity, assuming costs are non-negative. Since we are calculating Type 2 path cost, cost is 1.
        // We use a standard BFS since edge weights are uniform (1).

        dist_2.assign(N, -1); 
        q.clear();

        dist_2[L] = 0;
        q.push_back(L);
        int head = 0;

        while(head < q.size()) {
            int u = q[head++];

            if (u == R) {
                // We found the shortest path using only Type 2 moves
                min_cost = min(min_cost, dist_2[R]);
                // We can potentially break early if we only care about R, but we might need other intermediate nodes for the general case.
                // Since this is just path L->R via Type 2, we continue BFS until queue is empty or R is finalized.
            }

            int v = closest_index[u];
            if (v != -1 && dist_2[v] == -1) {
                dist_2[v] = dist_2[u] + 1;
                q.push_back(v);
            }
        }

        // The logic above only finds C_2(L, R). We must also consider the hybrid path:
        // L -> ... -> x (via Type 2, cost C_2(L, x)) -> R (via Type 1, cost abs(nums[x]-nums[R]))

        // We need to run Dijkstra/BFS from L to find the minimum cost C_2(L, x) for all x.

        vector<long long> dist_L(N, -1);
        vector<int> q_dijkstra;

        dist_L.assign(N, -1); 
        dist_L[L] = 0;
        q_dijkstra.push_back(L);

        // Since edge weights are 1, BFS is equivalent to Dijkstra.
        int head_dijkstra = 0;
        while(head_dijkstra < q_dijkstra.size()) {
            int u = q_dijkstra[head_dijkstra++];

            // Check hybrid path to R: L -> ... -> u (via Type 2) -> R (via Type 1)
            long long cost_hybrid = dist_L[u] + abs(nums[u] - nums[R]);
            min_cost = min(min_cost, cost_hybrid);

            // Explore Type 2 move from u
            int v = closest_index[u];
            if (v != -1 && dist_L[v] == -1) {
                dist_L[v] = dist_L[u] + 1;
                q_dijkstra.push_back(v);
            }
        }

        // The cost C_2(L, R) is covered when u=R in the loop above (Type 1 cost is abs(nums[R]-nums[R])=0, but Type 2 path cost is dist_L[R] which is found by BFS/Dijkstra).
        // We already initialized min_cost = abs(nums[L] - nums[R]), so if Type 2 path is shorter, it will be updated.

        return min_cost;
    }

public:
    vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
        // 1. Precompute closest indices
        precompute_closest(nums);

        vector<long long> ans;
        for (const auto& query : queries) {
            int L = query[0];
            int R = query[1];
            ans.push_back(solve_query(L, R, nums));
        }

        return ans;
    }
};

// Wrapper function to match the required signature
vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    Solution s;
    return s.solve(nums, queries);
}
